import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from 'src/environments/environment.prod';

import { Observable } from 'rxjs';


@Injectable({
  providedIn: 'root'
})
export class SecurityPolicyService {
API_URL=environment.MEDIAN_URL;
  constructor(private httpClient: HttpClient) { }

  saveDataSecurity(obj): Observable<any> {
    console.log(obj);
    return this.httpClient.post<any>(`${this.API_URL}/config/save`, obj)
  }
  fetchSecurityPolicyService() {
    return this.httpClient.get<any>(`${this.API_URL}/config/fetch`);
  }
  getSecurityPolicyForAuth() {
    return this.httpClient.get<any[]>(`${this.API_URL}/authorization/getSecurityPolicy`);
  }
  getMonitorData() {
    return this.httpClient.get<any>(`${this.API_URL}/excelDataForProcessScreeen/getMonitorData`);
  }
  // fetchSecurityPolicyService() {
  //   return this.httpClient.get<any>(`${API_URL}/securityPolicy/fetch`);
  // }
    changePassword(passwordDTO: object) {
    return this.httpClient.post<boolean>(`${this.API_URL}/user/changePassword`, passwordDTO);
  }
  //   fetchSecurityPolicyService() {
  //   return this.httpClient.get<any>(`${this.API_URL}/securityPolicy/fetch`);
  // }
}
